'legacy_l_115','legacy_u_8','32ft Motor Yacht',NULL,'A 1961 Akerboom sedan cruiser in need of total refurbishment. a great project for someone looking to restore a classic boat. also, if done properly a great opportunity to make money.',10000000,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'other' LIMIT 1),NULL,NULL,NULL,ARRAY['https://thereclaimedcompany.com/uploads/images/202107/img_1920x_60ffe78cdefdf4-22464894-25178324.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_60ffe78a2794c0-91661186-61145934.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_60ffe7883c89f8-14423541-89238199.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_60ffe786550354-21141834-50698422.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_60ffe784462848-35771569-96686740.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_60ffe782a1beb6-05632531-59209265.jpeg']::text[],'active','sell','LOT',NULL,false,NULL,NULL,true,'2021-07-27T11:06:01Z'::timestamptz,'2021-07-27T11:06:01Z'::timestamptz);

