) VALUES (
'legacy_l_117','legacy_u_8','Salt Glazed Wall Copings | Victorian Wall Copings',NULL,'I have 80 of these wall copings available to order. They are Victorian and salt glazed. They would be ideal for a renovaiton project to cap off a traditional brick wall. They provide a weatherproof capping and can be easly laid onto a damp proof course. National delivery can be offered to suit, ideally I am looking to sell all of them as a lot but may split them down into maller quantities if needed.',240000,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'other' LIMIT 1),NULL,0,0,ARRAY['https://thereclaimedcompany.com/uploads/images/202107/img_1920x_61010afa2726c7-77155699-76523318.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_61010b04aa0be9-18405193-21684726.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_61010b01cfbe87-39348084-70711155.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_61010afe66b447-94943379-40086703.jpeg']::text[],'active','sell','PER_UNIT',80,true,150,NULL,true,'2021-07-28T07:48:51Z'::timestamptz,'2021-07-28T07:48:51Z'::timestamptz);

INSERT INTO "Listing" (
"id","sellerId","title","sellerReference","description","price","condition","categoryId","postcode","lat","lng","images","status","listingKind","pricingMode","unitsAvailable","offersDelivery","deliveryCostPence","auctionEndsAt","visibleOnMarketplace","createdAt","updatedAt"
) VALUES (
'legacy_l_119','legacy_u_8','Large Banqueting table and chairs',NULL,'A large Banqueting table and several matching chairs. The table has been slavaged from York Guildhall and would be ideal for a marquee business or for use in a large office space as a meeting room centre piece. We have the table and chairs in a warehouse ready to ship nationally. The price inclides the table and all of the chairs. Buyer will be responible for collection and we can help with loading.',85000,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'other' LIMIT 1),'York',53.95996510000001,-1.0872979,ARRAY['https://thereclaimedcompany.com/uploads/images/202107/img_1920x_61010e7f255e70-93717950-38628505.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_61010e83a43e83-74538849-17931156.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_61010eb0118a34-89412168-13145612.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_61010eb23ef1e6-83389658-93839465.jpeg']::text[],'active','sell','LOT',NULL,true,100,NULL,true,'2021-07-28T07:58:54Z'::timestamptz,'2021-07-28T07:58:54Z'::timestamptz);

INSERT INTO "Listing" (
"id","sellerId","title","sellerReference","description","price","condition","categoryId","postcode","lat","lng","images","status","listingKind","pricingMode","unitsAvailable","offersDelivery","deliveryCostPence","auctionEndsAt","visibleOnMarketplace","createdAt","updatedAt"
) VALUES (
'legacy_l_120','legacy_u_8','Old Metal water tank',NULL,'Salvaged from an old property this fully enclosed metal water tank would be perfect for re purposing. This could be used as a table base or could easily be cut open to form a planter or decorative garden water feautre. The metal is very think and the tank extremely heavy. A rear old water tank due to the fact that is is completely enclosed. The tank is on the ground and I am happy to ship this anywhere in the UK. Shipping has been inclided in the price via a pallet network. If you are outside the UK this price will increase so please get in touch first.',30000,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'other' LIMIT 1),NULL,0,0,ARRAY['https://thereclaimedcompany.com/uploads/images/202107/img_1920x_61010fa1819a29-25380264-19100188.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_61010faa96c613-29872366-46741136.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_61010fa7740892-76243085-76407615.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_61010fa54b4548-80032321-47596897.jpeg']::text[],'active','sell','LOT',NULL,true,75,NULL,true,'2021-07-28T08:09:05Z'::timestamptz,'2021-07-28T08:09:05Z'::timestamptz);

INSERT INTO "Listing" (
"id","sellerId","title","sellerReference","description","price","condition","categoryId","postcode","lat","lng","images","status","listingKind","pricingMode","unitsAvailable","offersDelivery","deliveryCostPence","auctionEndsAt","visibleOnMarketplace","createdAt","updatedAt"
) VALUES (
'legacy_l_128','legacy_u_8','Handmade Roof tiles | William Blyth Medieval Clay Plain Tiles',NULL,'These handmade roof tiles are perfect for a roofing project. We have over 4000 tiles available which would be enough for 100m2 of roof area. New and unused William Blyth Medieval Clay Pantiles. These traditional handmade roof tiles would be perfect for a restoration project or barn conversion. Each tile is handmade and fittings for them are available from William Blyth. When laid on a roof the tiles provide a non-uniform appearance which looks great on period properties and are dark earth in colour. There is a deal to be done on the whole lot, which would suit a new build project. Delivery can be arranged and will be charged on a per pallet basis. If required, further tiles are available through us to match along with a range of fittings to match. These tiles would make the perfect roof covering for a heritage roofing project. Suited to barn conversions or houses where a traditional aesthetic is required. You can buy online here...',100,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'roof-tiles-slates' LIMIT 1),NULL,0,0,ARRAY['https://thereclaimedcompany.com/uploads/images/202107/img_1920x_61017be5d56cf3-43795327-12167103.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_61017c1dc48936-38760057-56862347.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_61017c17cfb867-03236248-48296351.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_61017be38662e6-58981905-14709983.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_61017be19d8fd7-52312876-57869763.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_61017bdf67f408-08811212-31123801.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_61017bdc55db56-31412332-56491023.jpeg']::text[],'active','sell','PER_UNIT',4000,true,500,NULL,true,'2021-07-28T15:50:14Z'::timestamptz,'2021-07-28T15:50:14Z'::timestamptz);

INSERT INTO "Listing" (
