) VALUES (
'legacy_l_132','legacy_u_8','Large Wooden Cable Reels',NULL,'Large timber cable reels, ideal for upcycling into garden tables or furniture. The price stated is for both of them, we are also happy to sell them individually. These cable reels are in stock and ready to dispatch. Shipping is avalable via a pallet network anywhere in the UK.',30000,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'other' LIMIT 1),NULL,NULL,NULL,ARRAY['https://thereclaimedcompany.com/uploads/images/202107/img_1920x_610280848caa69-09252520-63946709.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_61028076066084-87024099-74332088.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_610280728cf882-51979564-81277912.jpg']::text[],'active','sell','LOT',NULL,false,NULL,NULL,true,'2021-07-29T10:21:00Z'::timestamptz,'2021-07-29T10:21:00Z'::timestamptz);

