"id","sellerId","title","sellerReference","description","price","condition","categoryId","postcode","lat","lng","images","status","listingKind","pricingMode","unitsAvailable","offersDelivery","deliveryCostPence","auctionEndsAt","visibleOnMarketplace","createdAt","updatedAt"
) VALUES (
'legacy_l_136','legacy_u_3','Nordpeis Bergen ex-display wood burning stove',NULL,'Ex-display Nordpeis Bergen woodburner. Only been fired up a handful of times in our showroom, the stove is in perfect condition. Porcelain panels are not chipped, glass has no damage, door closes smoothly. 150 mm outlet, 5kW nominal output, A+ energy rating. UK delivery is included in the price.',62500,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'other' LIMIT 1),NULL,0,0,ARRAY['https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d0f945b529-37327774-80514325.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d12ee02225-45983806-67049955.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d12a028ec6-40875327-23484330.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d1244947b2-24598847-21349819.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d11f151da1-41490624-28751268.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d11ad52d23-04318690-51597517.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d1167022b6-50356116-49884282.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d111a79d40-58913975-30355760.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d10e71e2c6-59371752-14004004.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d10abc53b4-72386236-69303922.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d107644872-07666085-78835034.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d103e3fa40-23810339-53003289.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d10053fa43-92619447-65907486.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d0fcda4e40-82141003-14682161.jpg']::text[],'sold','sell','LOT',NULL,false,NULL,NULL,true,'2021-07-30T10:16:52Z'::timestamptz,'2021-07-30T10:16:52Z'::timestamptz);

INSERT INTO "Listing" (
"id","sellerId","title","sellerReference","description","price","condition","categoryId","postcode","lat","lng","images","status","listingKind","pricingMode","unitsAvailable","offersDelivery","deliveryCostPence","auctionEndsAt","visibleOnMarketplace","createdAt","updatedAt"
) VALUES (
'legacy_l_137','legacy_u_3','Nordpeis X25-F woodburner | Ex display, massive discount.',NULL,'Great quality second hand Nordpeis X25-F woodburning stove in good used condition. We just removed from a customer''s home where it serves perfectly for a few years. Vermiculite panels are perfect, no damage or crack, no damage on the glass, door closes fine, fire rope been changed recently. All the heat shields are included. 6.6 kW heat output, 150 mm flue outlet This stove is now discontinued and would make a superb garden fireplace installation. UK delivery at an addiitonal cost as outlined. This second hand woodburner is an absolute bargain.',50000,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'other' LIMIT 1),NULL,0,0,ARRAY['https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d3c044d204-78496425-45976101.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d401699aa0-77516960-67828735.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d3fc9f0664-15476143-32183070.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d3f7785cf6-49839274-53446854.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d3f2386a29-14651852-33665292.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d3ee4779b3-02083758-32510548.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d3eaed8419-99934042-84433734.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d3e75547f6-40086357-77022655.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d3e3b919e3-82839720-83261407.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d3df8a5a00-84155679-74187646.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d3db7ec7e4-07627701-23863563.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d3d6c70611-98372989-78215934.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d3d13d6896-07957078-11377356.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d3ca33fd33-72756908-79314164.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d3c487d079-75576473-49786104.jpg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6103d3b91be301-03338584-81621522.jpg']::text[],'active','sell','LOT',NULL,true,85,NULL,true,'2021-07-30T10:32:40Z'::timestamptz,'2021-07-30T10:32:40Z'::timestamptz);

INSERT INTO "Listing" (
"id","sellerId","title","sellerReference","description","price","condition","categoryId","postcode","lat","lng","images","status","listingKind","pricingMode","unitsAvailable","offersDelivery","deliveryCostPence","auctionEndsAt","visibleOnMarketplace","createdAt","updatedAt"
) VALUES (
'legacy_l_139','legacy_u_2','Reclaimed hardwood benches | Restaurant or bar seating',NULL,'Salvaged from the Guildhall in York, these timber benches are in need of some TLC. There are 6 old bench seats in total, all in varying states of disrepair. Likely more of interest for someone looking for good quality reclaimed timber or to be completely refurbished into restaurant or bar seating. The condiron of the timber is good but the upholstory, and associated horsehair stuffing, needs to be renewed. There are some decorative tirned feet which would look great if refurbihed. The items are sold as they are which is refelcetd in the price. Buyer is to collect from our premises at their costs. Payment via credit or debit card in advance of collection. These benches are a real part of York''s history, they would be ideal if you have the time and skills to give them a new lease of life. Further, once refurbished they are liklely to be worth much more per item than we are selling them for so it is a great opportunity for the right person to make some money.',35000,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'other' LIMIT 1),NULL,NULL,NULL,ARRAY['https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6105566b67d3e0-76494941-36821440.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_610556c2c4ce92-91718886-33954007.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_610556a6b693e5-29908947-72809686.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6105569b6e6416-31080299-12050751.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_6105568e70d449-55807162-15364117.jpeg','https://thereclaimedcompany.com/uploads/images/202107/img_1920x_61055681494420-47252469-90558832.jpeg']::text[],'active','sell','LOT',NULL,false,NULL,NULL,true,'2021-07-31T14:02:55Z'::timestamptz,'2021-07-31T14:02:55Z'::timestamptz);

