) VALUES (
'legacy_l_141','legacy_u_2','Sandtoft Neo Pantiles | Reclaimed but in great condition',NULL,'We have arond 3000 sandtoft Neo Pantiles, Flanders Red. Salvaged from a single source the tiles are saecond hand but had only been installed for around 8 years before being removed. Perfect for an extension roof area or for a re roofing project where a modern interlocking clay pantile is required. The price stated is per tile and we can arrange delivery as required based upon the qualitity ordered at an additional cost. Beat the waiting times for new roof tiles by buying these. Either buy online here or visit us directly at our online shop. Check out our video which showcases the quality of these second had roof tiles. https://youtu.be/P1ogXvjudFc',125,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'roof-tiles-slates' LIMIT 1),NULL,NULL,NULL,ARRAY['https://thereclaimedcompany.com/uploads/images/202108/img_1920x_61079d479b03e2-33659548-20267513.jpeg','https://thereclaimedcompany.com/uploads/images/202108/img_1920x_61079d54c938c9-52296940-20975810.jpeg','https://thereclaimedcompany.com/uploads/images/202108/img_1920x_61079d4f155aa9-71053307-69122021.jpeg']::text[],'active','sell','PER_UNIT',2000,false,NULL,NULL,true,'2021-08-02T07:26:15Z'::timestamptz,'2021-08-02T07:26:15Z'::timestamptz);

