'legacy_l_156','legacy_u_17','Salvaged Copper Street Lights',NULL,'London (Westminster) copper top Street lights in salvaged condition. One with its frog collar, Each light features its original plastic screen and attractive brass screws. Price per light. Get in touch to discuss national delivery or flexible collection. Height / 109cm Width / 42cm Height / 98cm Width / 42cm',0,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'hardware-fixtures' LIMIT 1),NULL,NULL,NULL,ARRAY['https://thereclaimedcompany.com/uploads/images/202108/img_1920x_61093407353a16-88707589-43547806.jpg']::text[],'active','sell','LOT',NULL,false,NULL,NULL,true,'2021-08-03T12:18:13Z'::timestamptz,'2021-08-03T12:18:13Z'::timestamptz);

