'legacy_l_158','legacy_u_17','Salvaged London Park Light',NULL,'A 1960''s Urbis Albany ''swan-neck'' lamp from a park in Westminster, London. Free-standing in a custom made base, perfect for lighting up a patio area. A real feature piece. Approx Height / 200cm Base Diameter / 80cm',43000,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'hardware-fixtures' LIMIT 1),NULL,NULL,NULL,ARRAY['https://thereclaimedcompany.com/uploads/images/202108/img_1920x_6109340da6eb00-78661423-34879377.jpg']::text[],'active','sell','LOT',NULL,false,NULL,NULL,true,'2021-08-03T12:18:21Z'::timestamptz,'2021-08-03T12:18:21Z'::timestamptz);

