INSERT INTO "Listing" (
"id","sellerId","title","sellerReference","description","price","condition","categoryId","postcode","lat","lng","images","status","listingKind","pricingMode","unitsAvailable","offersDelivery","deliveryCostPence","auctionEndsAt","visibleOnMarketplace","createdAt","updatedAt"
) VALUES (
'legacy_l_257','legacy_u_17','Extra Large Mythos Planter',NULL,'The extra large Mythos Cretan terracotta planter is the largest planter from my most popular ''Mythos'' range of tapered planters. Perfect for topiary, wild grasses and grand floral displays. I''ve planted some tall, hardy Salvia ''Amistad'' in my display. As a single feature or for dressing a terrace, these offer scale and impact. Get in touch to discuss national delivery or flexible collection. Cretan Terracotta Frost-Resistant Hand-Thrown Amazing colour Plants LOVE them Extra Large / Circa. 90 x 85cm Approximate 270 ltr capacity.',35000,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'other' LIMIT 1),NULL,NULL,NULL,ARRAY['https://thereclaimedcompany.com/uploads/images/202108/img_1920x_61094d5ebf5f32-13464311-73346967.jpg']::text[],'active','sell','LOT',NULL,false,NULL,NULL,true,'2021-08-03T14:06:22Z'::timestamptz,'2021-08-03T14:06:22Z'::timestamptz);

INSERT INTO "Listing" (
"id","sellerId","title","sellerReference","description","price","condition","categoryId","postcode","lat","lng","images","status","listingKind","pricingMode","unitsAvailable","offersDelivery","deliveryCostPence","auctionEndsAt","visibleOnMarketplace","createdAt","updatedAt"
) VALUES (
'legacy_l_258','legacy_u_17','Rhea Cretan Terracotta Planter',NULL,'Named after the Ancient Greek ''Mother of Gods'', the Rhea Cretan terracotta planter is a wide terracotta planter with generous room for shrubbery and specimen trees. Anything planted in this will be beautifully presented due to its raised profile and decorative handles. A classic Cretan look at a great price. Traditionally made from the finest Cretan clay and hand-thrown on a potters wheel. Get in touch to discuss national delivery. Two will fit on one pallet. Cretan Terracotta Frost-Resistant Hand-Thrown Amazing colour Plants LOVE them Height / 80cm Width / 80cm',35000,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'other' LIMIT 1),NULL,NULL,NULL,ARRAY['https://thereclaimedcompany.com/uploads/images/202108/img_1920x_61094d60b45fa9-83667464-73302435.jpg']::text[],'active','sell','LOT',NULL,false,NULL,NULL,true,'2021-08-03T14:06:23Z'::timestamptz,'2021-08-03T14:06:23Z'::timestamptz);

INSERT INTO "Listing" (
"id","sellerId","title","sellerReference","description","price","condition","categoryId","postcode","lat","lng","images","status","listingKind","pricingMode","unitsAvailable","offersDelivery","deliveryCostPence","auctionEndsAt","visibleOnMarketplace","createdAt","updatedAt"
) VALUES (
'legacy_l_259','legacy_u_17','Cretan Terracotta Pithoi',NULL,'This is the classic style of pot (Pithoi) that comes to mind when people mention Mediterranean pottery. Often used for specimen trees or as a stand-alone ornament. Traditionally made from the finest Cretan clay and spun on a potters wheel. Get in touch to discuss national delivery or flexible collection. Cretan Terracotta Frost-Resistant Hand-Thrown Amazing colour Plants LOVE them Large / 90 x 70cm Small / 70 x 65cm',22500,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'other' LIMIT 1),NULL,NULL,NULL,ARRAY['https://thereclaimedcompany.com/uploads/images/202108/img_1920x_61094d649204f6-97697701-92169634.jpg']::text[],'active','sell','LOT',NULL,false,NULL,NULL,true,'2021-08-03T14:06:27Z'::timestamptz,'2021-08-03T14:06:27Z'::timestamptz);

INSERT INTO "Listing" (
"id","sellerId","title","sellerReference","description","price","condition","categoryId","postcode","lat","lng","images","status","listingKind","pricingMode","unitsAvailable","offersDelivery","deliveryCostPence","auctionEndsAt","visibleOnMarketplace","createdAt","updatedAt"
) VALUES (
'legacy_l_260','legacy_u_17','Beehive Cretan Terracotta Pots',NULL,'Traditionally made from the finest Cretan clay and spun on a potters wheel, this is the king of decorative Cretan pots. Often used for specimen trees or as stand-alone ornaments, the Beehive features a ribbed body and is finished off with a simple rope-twist around the neck. Get in touch to discuss national delivery or flexible collection. Up to 2 large Beehive Pots can fit onto one pallet. Cretan Terracotta Frost-Resistant Hand-Thrown Amazing colour Plants LOVE them Should you be seeking to dress an Entrance Hall or Orangery with a Mediterranean flair, a bespoke oak plinth can be comissioned. For a special garden feature, a water pump could be installed allowing water to trickle over the lip and to cascade down the outide of the body',15000,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'other' LIMIT 1),NULL,NULL,NULL,ARRAY['https://thereclaimedcompany.com/uploads/images/202108/img_1920x_61094d68712ed2-61431717-99191149.jpg']::text[],'active','sell','LOT',NULL,false,NULL,NULL,true,'2021-08-03T14:06:30Z'::timestamptz,'2021-08-03T14:06:30Z'::timestamptz);

INSERT INTO "Listing" (
"id","sellerId","title","sellerReference","description","price","condition","categoryId","postcode","lat","lng","images","status","listingKind","pricingMode","unitsAvailable","offersDelivery","deliveryCostPence","auctionEndsAt","visibleOnMarketplace","createdAt","updatedAt"
) VALUES (
'legacy_l_261','legacy_u_17','Stefania Cretan Terracotta Planter',NULL,'The Stefania Cretan Terracotta Planter is an unusual tall but thin planter with straight sides - the perfect dressing for a front or back door. Great for showcasing small trees, topiary and swooping floral displays, this would also work placed at the back of a deep boarder. Traditionally made from the finest Cretan clay and thrown on a potters wheel. Get in touch to discuss national delivery or flexible collection. Multiple planters can fit on one pallet. Cretan Terracotta Frost-Resistant Hand-Thrown Amazing colour Plants LOVE them Height / 70cm Diameter / 45cm',14500,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'other' LIMIT 1),NULL,NULL,NULL,ARRAY['https://thereclaimedcompany.com/uploads/images/202108/img_1920x_61094d6c650769-05498589-64466293.jpg']::text[],'active','sell','LOT',NULL,false,NULL,NULL,true,'2021-08-03T14:06:34Z'::timestamptz,'2021-08-03T14:06:34Z'::timestamptz);

INSERT INTO "Listing" (
"id","sellerId","title","sellerReference","description","price","condition","categoryId","postcode","lat","lng","images","status","listingKind","pricingMode","unitsAvailable","offersDelivery","deliveryCostPence","auctionEndsAt","visibleOnMarketplace","createdAt","updatedAt"
) VALUES (
'legacy_l_262','legacy_u_17','Krotos Cretan Terracotta Jar',NULL,'Named after one of the most talented Satyrs in Greek mythology, the Krotos Cretan terracotta jar is a beautiful decoraitve vessel based on an ancient Cretan artifact. Traditionally made from the finest Cretan clay and spun on a potters wheel. Get in touch to discuss national delivery or flexible collection. Cretan Terracotta Frost-Resistant Hand-Thrown Amazing colour Plants LOVE them Height / 50cm Width / 35cm',8000,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'other' LIMIT 1),NULL,NULL,NULL,ARRAY['https://thereclaimedcompany.com/uploads/images/202108/img_1920x_61094d70330fb8-13582430-58659039.jpg']::text[],'active','sell','LOT',NULL,false,NULL,NULL,true,'2021-08-03T14:06:38Z'::timestamptz,'2021-08-03T14:06:38Z'::timestamptz);

