) VALUES (
'legacy_l_263','legacy_u_17','Chiron Cretan Terracotta Jugs',NULL,'Named after one of the great Centaurs in Greek mythology (a half man half horse), the Chiron Cretan terracotta jar is a beautiful decoraitve vessel based on an ancient Cretan artifact. Traditionally made from the finest Cretan clay and spun on a potters wheel. Get in touch to discuss national delivery or flexible collection. Cretan Terracotta Frost-Resistant Hand-Thrown Amazing colour Plants LOVE them Height / 50cm Width / 40cm',8500,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'other' LIMIT 1),NULL,NULL,NULL,ARRAY['https://thereclaimedcompany.com/uploads/images/202108/img_1920x_61094d742cbf21-59429839-17323711.jpg']::text[],'active','sell','LOT',NULL,false,NULL,NULL,true,'2021-08-03T14:06:42Z'::timestamptz,'2021-08-03T14:06:42Z'::timestamptz);

