) VALUES (
'legacy_l_265','legacy_u_17','Helios Cretan Terracotta Ribbed Pots',NULL,'A contemporary shaped ribbed planter, perfect for shrubs and eye-catching specimens like Choisya Ternata ''Aztec'' Pearl. Whilst not hand-thrown, this is made in a mould from the same clay and put through the same intense firing process as my main range of Cretan terracotta. All in the same Pottery on Crete. Get in touch to discuss national delivery or flexible collection. A large quantity of these may fit on a pallet. Cretan Terracotta Frost-Resistant Amazing colour Plants LOVE them Hybrid Design Height / 37cm Diameter / 45cm',8000,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'other' LIMIT 1),NULL,NULL,NULL,ARRAY['https://thereclaimedcompany.com/uploads/images/202108/img_1920x_61094d7bb86a73-93612650-69270347.jpg']::text[],'active','sell','LOT',NULL,false,NULL,NULL,true,'2021-08-03T14:06:50Z'::timestamptz,'2021-08-03T14:06:50Z'::timestamptz);

