) VALUES (
'legacy_l_328','legacy_u_2','Large and Very secure safe from 1971 | Sargent & Greenleaf Inc lock mechanism.',NULL,'What a find! This safe, was seemingly made for or by Rolls Royce in 1971. A company called Sargent & Greenleaf from kentucky made the lock for this safe. The safe is very large and extremely heavy. There are two locking mechansms, a code lock, we have the code, and a set of keys and key lock also. It would be a shame to see this safe sold for scrap and we are happy to look at offers. It would be perfect for someone who wants a real feature pr for storage of valuables in an existing business. Buyer to collect or we can arrange delivery anywhere in the UK at an additional cost. If you are interested in this item then please get in touch. We will only accept payments made through The Reclaimed Company, no cash on collection.',120000,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'other' LIMIT 1),NULL,NULL,NULL,ARRAY['https://thereclaimedcompany.com/uploads/images/202108/img_1920x_6113d5793c58a9-44092901-13985807.jpeg','https://thereclaimedcompany.com/uploads/images/202108/img_1920x_6113d5575a7b25-22516968-11629806.jpeg','https://thereclaimedcompany.com/uploads/images/202108/img_1920x_6113d55d4061e8-25504228-41573359.jpeg','https://thereclaimedcompany.com/uploads/images/202108/img_1920x_6113d56412a4b7-52053185-70255482.jpeg','https://thereclaimedcompany.com/uploads/images/202108/img_1920x_6113d5696626d2-26190118-91169893.jpeg','https://thereclaimedcompany.com/uploads/images/202108/img_1920x_6113d56e992837-24754852-88128503.jpeg','https://thereclaimedcompany.com/uploads/images/202108/img_1920x_6113d57deffb58-29918065-91572664.jpeg','https://thereclaimedcompany.com/uploads/images/202108/img_1920x_6113d58389cba6-00266424-37474596.jpeg','https://thereclaimedcompany.com/uploads/images/202108/img_1920x_6113d58a661d32-46336608-97049367.jpeg','https://thereclaimedcompany.com/uploads/images/202108/img_1920x_6113d590a7df88-83557476-24430641.jpeg','https://therecl