) VALUES (
'legacy_l_377','legacy_u_68','6 Pack Reclaimed Redland Cambrian Roof Tiles in Slate Grey',NULL,'6 Pack Reclaimed Redland Cambrian Roof Tiles in Slate Grey 6 Pack of Reclaimed Redland Cambrian roof tiles in slate grey. Great condition for a reclaimed tile. Stored indoors since reclamation. Cambrian Slates embody the beauty and character of natural slate. Made in Wales from over 60% recycled Welsh slate, Cambrian tops the range in both looks and performance and has a proven track record even on pitches as low as 15°. Whilst light in weight, Cambrian''s unique three point fixing makes it suitable for even the most exposed sites.',2160,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'roof-tiles-slates' LIMIT 1),'Yo32 2rb',54.0297918,-1.0963469,ARRAY['https://thereclaimedcompany.com/uploads/images/202202/img_1920x_61f913bcccb651-28088820-83608050.jpeg','https://thereclaimedcompany.com/uploads/images/202202/img_1920x_61f90b5debd090-94841187-76667970.jpeg','https://thereclaimedcompany.com/uploads/images/202202/img_1920x_61f90b5726e632-45086765-43925317.jpeg']::text[],'active','sell','PER_UNIT',3,true,24,NULL,true,'2022-02-01T10:54:57Z'::timestamptz,'2022-02-01T10:54:57Z'::timestamptz);

