'legacy_l_401','legacy_u_109','Reclaimed clay roof tiles',NULL,'Reclaimed clay roof tiles, in good condition, for sale. Must be collected by Wednesday 11th May 2022. Any questions, or would like more pictures / information, please do not hesitate to get in touch. Arches available too. COLLECTION ONLY',10000,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'roof-tiles-slates' LIMIT 1),'Tw200rp',51.4276974,-0.5709226,ARRAY['https://thereclaimedcompany.com/uploads/images/202205/img_1920x_6273910c8bd679-38144725-25396286.jpg','https://thereclaimedcompany.com/uploads/images/202205/img_1920x_62739107ad1c23-88633287-68883197.jpg']::text[],'active','sell','PER_UNIT',200,false,NULL,NULL,true,'2022-05-05T09:03:36Z'::timestamptz,'2022-05-05T09:03:36Z'::timestamptz);

INSERT INTO "Listing" (
"id","sellerId","title","sellerReference","description","price","condition","categoryId","postcode","lat","lng","images","status","listingKind","pricingMode","unitsAvailable","offersDelivery","deliveryCostPence","auctionEndsAt","visibleOnMarketplace","createdAt","updatedAt"
) VALUES (
'legacy_l_402','legacy_u_111','Forticrete Anchor Anchorlite Roof Tiles',NULL,'£2 per tile Approximately 2000 Anchorlite Tiles For Sale. Approx 300 per crate. Almost 7 crates. I believe this tile to be discontinued and hard to get hold of. I can arrange a handler to load the crates into a vehicle. You will have to arrange pickup or collection from DG9 postcode. General condition of tiles can be seen in the above pics. Some are cleaner, some aren''t. They have been sat on the roof for 25 years. Any further questions just get in touch. Thanks. MORE INFORMATION The Forticrete Anchorlite tile is small, lightweight single-interlocking. It is a “slate-effect” tile. The rear of the tile shows the name ‘Anchor’ and also has two small slim support nibs. The Anchorlite has now discontinued. Measurements per tile 13″ x 11″ x 1″ 33cm x 28 cm x 2.5cm 2 Kg Forticrete Forticrete’s range of concrete roof tiles, cast stone, walling stone & architectural masonry are unrivalled. They are evolving with over five decades of experience. Working closely with their customers in the UK construction industry. Forticrete have used their technical know how to adapt to the ever-changing needs in the market. Forticrete have made tiles that provide a balance of aesthetics, capability and also value. Innovation and Awards Forticrete has long been the driving force at the forefront of innovation in masonry as well as product development. The Gemini concrete roofing tile Awarded the Millennium Products status by the Design Council. Queen’s Award for Enterprise in Innovation. History During the late 1920’s Forticrete was founded as The Wilkinson Brothers of Liverpool. The name then became the Northern Cement Construction Company. Originally they made bricks, pipes, tiles and terracotta. Expansion followed into precast concrete as well as flagstones. The name Forticrete began as a brand during WWII and it was in 1959 when the company became part of Roadstone. This is when the company that exists today truly came into being. The company grew with the acquisition of Hardrow manufacturer, Robert Abraham in 1981. The next to be bought were firstly Wath Concrete followed by Anchor Roofing and Newlay Concrete. In 1999, Ibstock joined the same group. Forticrete then added the Walling and Cast Stone product range into the business.',200,'used',(SELECT "id" FROM "Category" WHERE "slug" = 'roof-tiles-slates' LIMIT 1),'dg9 0qb ',54.9709719,-5.1554474,ARRAY['https://thereclaimedcompany.com/uploads/images/202205/img_1920x_627547fe6f9627-70446421-67171436.jpg','https://thereclaimedcompany.com/uploads/images/202205/img_1920x_627547e9c14085-56103662-14579187.jpg','https://thereclaimedcompany.com/uploads/images/202205/img_1920x_627547b10a2548-10286497-14448085.jpg','https://thereclaimedcompany.com/uploads/images/202205/img_1920x_62754797782a06-71527549-29410208.jpg','https://thereclaimedcompany.com/uploads/images/202205/img_1920x_627f9c93db1853-04122922-76981998.jpg']::text[],'active','sell','PER_UNIT',2000,true,1000,NULL,true,'2022-05-06T16:40:09Z'::timestamptz,'2022-05-06T16:40:09Z'::timestamptz);

